# ============================================================
# adhd_crown.py
# EEG-FM-Bench dataset builder for the 8-channel Neurosity Crown
# version of the ADHD dataset.
#
# This is a mirror of adhd.py but adapted for the Crown montage:
#   - 8 channels: F5, F6, C3, C4, CP3, CP4, PO3, PO4
#   - Read from ADHD_Crown/ (generated by crown_dataset_builder.py)
#   - Uses 10-10 montage (standard_1005 in MNE contains both 10-20 and 10-10)
#
# Same 121 subjects, same train/val/test split, same labels.
# Only the channel configuration differs.
# ============================================================

import logging
import os
from dataclasses import dataclass, field
from typing import Optional, Union, Any

import datasets
import mne
import numpy as np
import pandas as pd
from pandas import DataFrame

from common.type import DatasetTaskType
from data.processor.builder import EEGConfig, EEGDatasetBuilder

logger = logging.getLogger('preproc')


# ===========================================================================
# CONFIGURATION
# ===========================================================================

@dataclass
class ADHDCrownConfig(EEGConfig):

    name: str = 'pretrain'

    version: Optional[Union[datasets.utils.Version, str]] = datasets.utils.Version("1.0.0")

    description: Optional[str] = (
        "8-channel Neurosity Crown EEG dataset for ADHD classification. "
        "Derived from the 19-channel ADHD dataset via MNE spherical spline "
        "interpolation to match the Crown EEG montage. "
        "121 children (61 ADHD, 60 Control), recorded at 128 Hz."
    )

    citation: Optional[str] = """\
    @data{bhd5-j477-22,
    doi = {10.21227/bhd5-j477},
    author = {Nasrabadi, Ali Motie},
    title = {EEG Data for ADHD / Control Children},
    publisher = {IEEE Dataport},
    year = {2020}
    }
    """

    filter_notch: float = 50.0
    is_notched: bool = False

    # Key used in wrapper.py's DATASET_SELECTOR to find this builder by name
    dataset_name: Optional[str] = 'adhd_crown'

    task_type: DatasetTaskType = DatasetTaskType.CLINICAL
    file_ext: str = 'csv'

    # ------------------------------------------------------------------
    # The 8 Neurosity Crown channel names, UPPERCASED.
    #
    # Crown channel positions:
    #   - F5, F6:   10-10 frontal (between F3-F7 and F4-F8 respectively)
    #   - C3, C4:   10-20 central (motor cortex, same as standard)
    #   - CP3, CP4: 10-10 centro-parietal (between C3-P3 and C4-P4)
    #   - PO3, PO4: 10-10 parieto-occipital (between P3-O1 and P4-O2)
    #
    # Note: F5/F6/CP3/CP4/PO3/PO4 are 10-10 positions, NOT in standard 10-20.
    # We use 'standard_1005' montage in MNE which contains all 10-10 positions.
    # ------------------------------------------------------------------
    montage: dict[str, list[str]] = field(default_factory=lambda: {
        '10_10': [
            'F5',  'F6',
            'C3',  'C4',
            'CP3', 'CP4',
            'PO3', 'PO4',
        ]
    })

    valid_ratio: float = 0.15
    test_ratio: float = 0.15

    # Same window lengths as adhd.py
    wnd_div_sec: int = 10

    # ------------------------------------------------------------------
    # Folder structure:
    #   <raw_path>/
    #       ADHD_Crown/                ← generated by crown_dataset_builder.py
    #           subjects/              ← 121 per-subject CSVs (8 channels each)
    #               v10p.csv
    #               v107.csv
    #               ...
    #           summary/               ← copied from ADHD/
    #               finetune/
    #                   adhd_finetune_info.csv
    #
    # Note: there is NO master adhdata.csv in ADHD_Crown/.
    # The crown_dataset_builder.py creates per-subject files directly.
    # ------------------------------------------------------------------
    suffix_path: str = 'ADHD_Crown'
    scan_sub_dir: str = 'subjects'

    category: list[str] = field(default_factory=lambda: ['ADHD', 'Control'])


# ===========================================================================
# BUILDER
# ===========================================================================

class ADHDCrownBuilder(EEGDatasetBuilder):

    BUILDER_CONFIG_CLASS = ADHDCrownConfig

    BUILDER_CONFIGS = [
        BUILDER_CONFIG_CLASS(name='pretrain'),
        BUILDER_CONFIG_CLASS(name='finetune', is_finetune=True, wnd_div_sec=4),
    ]

    def __init__(self, config_name='pretrain', **kwargs):
        super().__init__(config_name, **kwargs)
        self._load_meta_info()

    # ------------------------------------------------------------------
    # _load_meta_info
    # ------------------------------------------------------------------
    # Unlike adhd.py, we do NOT split a master CSV here.
    # The crown_dataset_builder.py script has already generated the
    # per-subject CSVs directly into ADHD_Crown/subjects/.
    #
    # This method just reads the labels from each per-subject CSV
    # (from the 'Class' column) and builds self.sub_meta.
    # ------------------------------------------------------------------
    def _load_meta_info(self):
        subjects_dir = os.path.join(self.config.raw_path, self.config.scan_sub_dir)

        if not os.path.exists(subjects_dir):
            raise FileNotFoundError(
                f"Subjects directory not found: {subjects_dir}\n"
                f"Please run crown_dataset_builder.py first to generate "
                f"the 8-channel Crown dataset from the 19-channel ADHD dataset."
            )

        csv_files = sorted(f for f in os.listdir(subjects_dir) if f.endswith('.csv'))
        if not csv_files:
            raise ValueError(
                f"No CSV files found in {subjects_dir}\n"
                f"Run crown_dataset_builder.py to generate them."
            )

        logger.info(f"Loading metadata from {len(csv_files)} per-subject CSVs")

        records = []
        for fname in csv_files:
            subject_id = fname.replace('.csv', '')
            subject_path = os.path.join(subjects_dir, fname)

            # Read just first row for the label — faster than full file
            try:
                df = pd.read_csv(subject_path, nrows=1)
                if 'Class' not in df.columns:
                    raise ValueError(f"'Class' column missing in {fname}")
                label = str(df['Class'].iloc[0])
            except Exception as e:
                logger.error(f"Failed to read {fname}: {e}")
                continue

            records.append({
                'subject': subject_id,
                'label':   label,
            })

        self.sub_meta = pd.DataFrame(records)

        n_adhd = len(self.sub_meta[self.sub_meta['label'] == 'ADHD'])
        n_ctrl = len(self.sub_meta[self.sub_meta['label'] == 'Control'])
        logger.info(f"Metadata ready: {n_adhd} ADHD, {n_ctrl} Control subjects")

    # ------------------------------------------------------------------
    # _walk_raw_data_files
    # ------------------------------------------------------------------
    def _walk_raw_data_files(self):
        subjects_dir = os.path.join(self.config.raw_path, self.config.scan_sub_dir)
        raw_data_files = []

        for fname in sorted(os.listdir(subjects_dir)):
            if fname.endswith('.csv'):
                full_path = os.path.join(subjects_dir, fname)
                raw_data_files.append(os.path.normpath(full_path))

        logger.info(f"Found {len(raw_data_files)} subject files to process.")
        return raw_data_files

    # ------------------------------------------------------------------
    # _resolve_file_name
    # ------------------------------------------------------------------
    def _resolve_file_name(self, file_path: str) -> dict[str, Any]:
        subject_id = self._extract_file_name(file_path)
        return {
            'subject': subject_id,
            'session': 1,
        }

    # ------------------------------------------------------------------
    # _resolve_exp_meta_info
    # ------------------------------------------------------------------
    def _resolve_exp_meta_info(self, file_path: str) -> dict[str, Any]:
        info = self._resolve_file_name(file_path)
        subject_id = info['subject']

        row = self.sub_meta[self.sub_meta['subject'] == subject_id]
        label = row['label'].iloc[0] if not row.empty else 'Unknown'

        df = pd.read_csv(file_path)
        n_samples = len(df)
        duration = n_samples / 128.0

        info.update({
            'montage': '10_10',     # Crown uses 10-10 system
            'time':    duration,
            'group':   label,
            'age':     -1,
            'sex':     'U',
        })

        return info

    # ------------------------------------------------------------------
    # _resolve_exp_events
    # ------------------------------------------------------------------
    def _resolve_exp_events(self, file_path: str, info: dict[str, Any]):
        if not self.config.is_finetune:
            return [('default', 0, -1)]

        group = info['group']
        return [(group, 0, -1)]

    # ------------------------------------------------------------------
    # _divide_split
    # ------------------------------------------------------------------
    def _divide_split(self, df: DataFrame) -> DataFrame:
        if self.config.is_finetune:
            df = self._divide_label_balance_all_split(df)
        else:
            df = self._divide_label_balance_all_split(df, splits=['train', 'valid'])
        return df

    # ------------------------------------------------------------------
    # standardize_chs_names
    # ------------------------------------------------------------------
    # Crown channel names (F5, F6, C3, C4, CP3, CP4, PO3, PO4) are already
    # standard names and don't need alias replacement.
    # We still apply the parent's replace dict for safety/consistency.
    # ------------------------------------------------------------------
    def standardize_chs_names(self, montage: str):
        if montage in self._std_chs_cache.keys():
            return self._std_chs_cache[montage]

        chs: list[str] = self.config.montage[montage]
        chs_std = [self.montage_10_20_replace_dict.get(ch, ch) for ch in chs]
        self._std_chs_cache[montage] = chs_std
        return chs_std

    # ------------------------------------------------------------------
    # _read_raw_data
    # ------------------------------------------------------------------
    # Read one subject's 8-channel CSV and convert to MNE Raw.
    #
    # Steps:
    #   1. Read CSV (8 EEG columns + Class + ID)
    #   2. Select the 8 EEG channel columns (case-insensitive)
    #   3. Transpose (timepoints × channels) → (channels × timepoints)
    #   4. Convert µV → V
    #   5. Create MNE Info + RawArray
    #   6. Attach standard_1005 montage (contains 10-10 positions for Crown)
    # ------------------------------------------------------------------
    def _read_raw_data(self, file_path: str, preload: bool = True, verbose: bool = False):

        # Step 1: Read CSV
        df = pd.read_csv(file_path)

        # Step 2: Case-insensitive column lookup
        csv_cols_upper = {c.upper(): c for c in df.columns}
        channel_names_upper = self.config.montage['10_10']

        try:
            selected_cols = [csv_cols_upper[ch] for ch in channel_names_upper]
        except KeyError as e:
            raise ValueError(
                f"Missing channel {e} in {file_path}. "
                f"Expected channels: {channel_names_upper}"
            )

        eeg_df = df[selected_cols]

        # Step 3: Transpose
        data = eeg_df.values.T.astype(np.float64)

        # Step 4: µV → V
        data = data * 1e-6

        # Step 5: Create MNE Info + RawArray
        info = mne.create_info(
            ch_names=channel_names_upper,
            sfreq=128.0,
            ch_types='eeg',
        )
        raw = mne.io.RawArray(data, info, verbose=verbose)

        # Step 6: Set standard_1005 montage
        # This montage contains positions for both 10-20 and 10-10 channels,
        # so Crown's F5/F6/CP3/CP4/PO3/PO4 are recognized.
        dig_montage = mne.channels.make_standard_montage('standard_1005')
        raw.set_montage(dig_montage, match_case=False,
                        on_missing='ignore', verbose=verbose)

        return raw


# ===========================================================================
# STANDALONE TEST
# Run this file directly to test:
#   python data/dataset/adhd_crown.py
# ===========================================================================

if __name__ == "__main__":
    builder = ADHDCrownBuilder("finetune")
    # Uncomment to wipe cached data and start completely fresh:
    # builder.clean_disk_cache()
    # builder.preproc(n_proc=1)
    builder.download_and_prepare(num_proc=1)
    dataset = builder.as_dataset()
    print(dataset)
